private IneqTree Balls()
{
	var res = new IneqTree();	

  	var pol = Ineq3DOnline.PlatonicSolids.Polyhedron.CreateIcosahedron();

    foreach (var v in pol.Vertices)
    {
		res = res | Ball(v.X, v.Y, v.Z, 0.18);
    } 
  
   	return res;
}

private IneqTree Balls1()
{
	var res = new IneqTree();	

  	var pol = Ineq3DOnline.PlatonicSolids.Polyhedron.CreateIcosahedron();

  
  	foreach (var e in pol.Edges)
    {
		var v1 = pol.Vertices[e.Item1];
      	var v2 = pol.Vertices[e.Item2];
      	var v = ((v1 + v2)/2).Normalize();
      	res = res | Ball(v.X, v.Y, v.Z, 0.18);
    }
  
   	return res;
}


public IneqMesh GetIneqMesh()
{
  	var res = Ball(0,0,0,1) & !Balls() & !Balls1();
  
  	res.Transform(delegate(ref double x, ref double y, ref double z) 
	{
		double s1 = 1.2;
      	double s2 = 1.7;
      
      	double s = s1 + (s2-s1)*(z+1)/2;
      
      	x *= s; y *= s; //z *= 2.0d;  
    });
  
    return new IneqMesh
    {
        X0 = -1.8,
        Y0 = -1.8,
        Z0 = -1.8,
        X1 = 1.8,
        Y1 = 1.8,
        Z1 = 1.8,
        D = 0.1d,
        Boxed = true,
        IneqTree = res
	};
}
